INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'B1', 'listening', 'The Bustling Station', 'Listen to the sounds of a railway station', '{"type":"listen_and_choose","instructions":"Listen to the sound description and choose the correct interpretation.","exercises":[{"prompt":"The sharp whistle of a steam engine echoed through the vaulted ceiling.","options":["🚆 Train","🛳️ Ship","✈️ Plane","🚗 Car"],"correct":0,"hint":"Sharp steam whistle"},{"prompt":"The rhythmic clatter of wheels on tracks grew louder.","options":["🚲 Cycle","🚃 Train","🚜 Tractor","🚁 Drone"],"correct":1,"hint":"Wheels on tracks"},{"prompt":"Announcement: The 10:15 to London is now boarding at platform four.","options":["🏨 Hotel","🏢 Office","🚉 Station","🏫 School"],"correct":2,"hint":"Platform 4"},{"prompt":"Muffled chatter of hundreds of travelers in the waiting room.","options":["🎭 Theater","🏛️ Museum","🚉 Hall","🌳 Park"],"correct":2,"hint":"Travelers in hall"},{"prompt":"Scraping sound of heavy suitcases being dragged.","options":["🧳 Luggage","🧹 Cleaning","🔨 Construction","🎹 Piano"],"correct":0,"hint":"Dragging suitcases"}]}', 11),
('en', 'B1', 'listening', 'City Rhythms', 'Identify the layered sounds of an urban environment', '{"type":"listen_and_choose","instructions":"Identify the primary urban sound described.","exercises":[{"prompt":"The distant wail of a siren cut through the midnight silence.","options":["🚑 Siren","🎶 Concert","🌬️ Wind","🐶 Dog"],"correct":0,"hint":"Emergency wail"},{"prompt":"The steady hum of traffic on the highway below.","options":["🐝 Bees","🚗 Cars","🌊 Waves","📻 Radio"],"correct":1,"hint":"Highway hum"},{"prompt":"The bright jingle of a bicycle bell.","options":["🔔 Bell","🚪 Doorbell","📱 Phone","🎸 Guitar"],"correct":0,"hint":"Cyclist warning"},{"prompt":"The heavy thud of a pile driver at a construction site.","options":["🔨 Construction","🌩️ Thunder","🥁 Drums","🏀 Ball"],"correct":0,"hint":"Construction thud"},{"prompt":"The melodic chirping of birds in the city park at sunrise.","options":["🐦 Birds","🦗 Crickets","🐈 Cats","🐒 Monkeys"],"correct":0,"hint":"Morning birds"}]}', 12),
('en', 'B1', 'listening', 'Nature Symphony', 'Listen to natural audio landscapes', '{"type":"listen_and_choose","instructions":"Match the sound description to the image.","exercises":[{"prompt":"The thunderous roar of a waterfall.","options":["🌊 Waterfall","🌧️ Rain","🥤 Drink","🛁 Shower"],"correct":0,"hint":"Roaring water"},{"prompt":"The gentle rustle of dry leaves underfoot.","options":["🍂 Leaves","🔥 Fire","🍿 Popcorn","📄 Paper"],"correct":0,"hint":"Autumn rustle"},{"prompt":"The crashing of waves against jagged rocks.","options":["🌊 Sea","🚿 Shower","☕ Coffee","🍵 Tea"],"correct":0,"hint":"Breaking waves"},{"prompt":"The crackling of a campfire in the silent wilderness.","options":["🔥 Campfire","🎆 Fireworks","🔫 Gunshot","🍳 Pan"],"correct":0,"hint":"Crackling wood"},{"prompt":"The howling wind during a blizzard.","options":["❄️ Blizzard","🦁 Lion","🚗 Car","🚂 Train"],"correct":0,"hint":"Howling cold"}]}', 13),
('en', 'B1', 'listening', 'Workplace Atmosphere', 'Identify sounds in a modern office', '{"type":"listen_and_choose","instructions":"Choose the equipment based on the sound.","exercises":[{"prompt":"The rapid-fire clicking of mechanical keyboards.","options":["💻 Keyboards","🖱️ Mice","⏰ Clocks","🔨 Hammers"],"correct":0,"hint":"Key clicking"},{"prompt":"The whirring and beeping of the photocopier.","options":["📠 Copier","📠 Fax","☕ Coffee","🌬️ Fan"],"correct":0,"hint":"Copier whirring"},{"prompt":"The soft chime of an incoming video call.","options":["💻 Video call","🔔 Doorbell","⏰ Alarm","📢 Announcement"],"correct":0,"hint":"Call chime"},{"prompt":"The hiss of the espresso machine in the breakroom.","options":["☕ Espresso","🐍 Snake","🎈 Balloon","🚿 Shower"],"correct":0,"hint":"Steaming coffee"},{"prompt":"The low murmur of colleagues in a meeting.","options":["👥 Meeting","🎤 Concert","📣 Protest","🤫 Secret"],"correct":0,"hint":"Talking colleagues"}]}', 14),
('en', 'B1', 'listening', 'The Kitchen Ballet', 'Sounds of cooking a complex meal', '{"type":"listen_and_choose","instructions":"Identify the kitchen activity.","exercises":[{"prompt":"The rhythmic chopping of vegetables.","options":["🔪 Chopping","🥣 Stirring","🔥 Frying","🧂 Seasoning"],"correct":0,"hint":"Knife on board"},{"prompt":"The aggressive sizzle of a steak.","options":["🥩 Steak","🍲 Soup","🧊 Ice","🍞 Toast"],"correct":0,"hint":"Hot skillet sizzle"},{"prompt":"The metallic clink of a whisk against a glass bowl.","options":["🥚 Whisking","🥄 Eating","🍽️ Table","🍷 Wine"],"correct":0,"hint":"Beating eggs"},{"prompt":"The high-pitched whistle of a teakettle.","options":["🫖 Teakettle","🚂 Train","🌬️ Wind","🐦 Bird"],"correct":0,"hint":"Boiling water"},{"prompt":"The satisfying pop of a wine cork.","options":["🍾 Cork","🎈 Balloon","💥 Firework","🔫 Toy"],"correct":0,"hint":"Opening bottle"}]}', 15),
('en', 'B1', 'listening', 'Evening Entertainment', 'Sounds from a theater', '{"type":"listen_and_choose","instructions":"Identify the performance sound.","exercises":[{"prompt":"The collective gasp of the audience.","options":["😲 Gasping","👏 Clapping","😂 Laughing","😢 Crying"],"correct":0,"hint":"Surprised audience"},{"prompt":"An orchestra tuning their instruments.","options":["🎻 Tuning","🎼 Playing","👏 Applauding","🤫 Shushing"],"correct":0,"hint":"Before playing"},{"prompt":"Thunderous applause as the curtain fell.","options":["👏 Applause","🌧️ Thunder","🌊 Waves","🚁 Helicopter"],"correct":0,"hint":"End of show"},{"prompt":"Delicate tinkling of a piano sonata.","options":["🎹 Piano","🎻 Violin","🎺 Trumpet","🥁 Drums"],"correct":0,"hint":"Piano keys"},{"prompt":"Muffled laughter ripples through the rows.","options":["🎭 Comedy","🏟️ Match","🏥 Hospital","🏦 Bank"],"correct":0,"hint":"Funny moment"}]}', 16),
('en', 'B1', 'listening', 'Morning at Home', 'Daily routine sounds', '{"type":"listen_and_choose","instructions":"What part of the morning is this?","exercises":[{"prompt":"The persistent buzzing of an alarm clock.","options":["⏰ Waking","☕ Breakfast","🚿 Shower","🚗 Travel"],"correct":0,"hint":"Buzzing alarm"},{"prompt":"The gushing sound of the shower.","options":["🚿 Shower","🌧️ Rain","🌊 Swimming","☕ Drink"],"correct":0,"hint":"Water in bathroom"},{"prompt":"Scraping a knife spreading butter on toast.","options":["🍞 Breakfast","🧹 Cleaning","🔨 DIY","🎹 Music"],"correct":0,"hint":"Butter on toast"},{"prompt":"Electronic beep of the microwave.","options":["🍱 Microwave","📺 TV","📱 Phone","🚪 Door"],"correct":0,"hint":"Heating food"},{"prompt":"Jingling of keys before leaving.","options":["🔑 Leaving","🛌 Sleeping","🍳 Cooking","📖 Reading"],"correct":0,"hint":"Keys in hand"}]}', 17),
('en', 'B1', 'listening', 'The Secret Garden', 'Soft sounds of a sanctuary', '{"type":"listen_and_choose","instructions":"Identify the delicate sound.","exercises":[{"prompt":"Splashing of a small fountain.","options":["⛲ Fountain","🚿 Shower","🌧️ Rain","🍵 Tea"],"correct":0,"hint":"Courtyard water"},{"prompt":"Buzzing of a bumblebee.","options":["🐝 Bee","🚁 Drone","🏎️ Car","📻 Radio"],"correct":0,"hint":"Insect in garden"},{"prompt":"Rhythmic creak of a wooden gate.","options":["🚪 Gate","🪑 Chair","👣 Steps","🔨 Hammer"],"correct":0,"hint":"Opening gate"},{"prompt":"Distant tolling of a church bell.","options":["🔔 Bell","📱 Phone","⏰ Alarm","📢 Siren"],"correct":0,"hint":"Church sound"},{"prompt":"Soft flutter of butterfly wings.","options":["🦋 Butterfly","🦅 Eagle","✈️ Plane","🚁 Helicopter"],"correct":0,"hint":"Small wings"}]}', 18),
('en', 'B1', 'listening', 'Stormy Night', 'Intense weather sounds', '{"type":"listen_and_choose","instructions":"Identify the storm element.","exercises":[{"prompt":"Rolling rumble of thunder.","options":["🌩️ Thunder","🚜 Tractor","🚂 Train","🥁 Drums"],"correct":0,"hint":"Rumble in sky"},{"prompt":"Rhythmic drum of heavy rain.","options":["🌧️ Rain","👏 Applause","🍿 Popcorn","🔨 Hammer"],"correct":0,"hint":"Rain on roof"},{"prompt":"Sudden crack of lightning.","options":["⚡ Lightning","💥 Explosion","🔫 Gunshot","🔨 Wood"],"correct":0,"hint":"Electric crack"},{"prompt":"Whistling wind through the eaves.","options":["🌬️ Wind","🫖 Teakettle","🚂 Train","🐦 Bird"],"correct":0,"hint":"Air in eaves"},{"prompt":"Splash of a car through a puddle.","options":["🚗 Puddle","🚿 Shower","🌊 Ocean","☕ Drink"],"correct":0,"hint":"Road splash"}]}', 19),
('en', 'B1', 'listening', 'The Workshop', 'Manual labor sounds', '{"type":"listen_and_choose","instructions":"Which tool is described?","exercises":[{"prompt":"Shrill whine of a circular saw.","options":["🪚 Saw","🔨 Hammer","🪛 Tool","📏 Ruler"],"correct":0,"hint":"Sawing wood"},{"prompt":"Thud of a blacksmith''s hammer.","options":["🔨 Blacksmith","🪓 Chopping","🥁 Drum","👟 Running"],"correct":0,"hint":"Iron work"},{"prompt":"Scratching of sandpaper.","options":["🪵 Sandpaper","🧹 Broom","🖊️ Pen","🐈 Cat"],"correct":0,"hint":"Smoothing wood"},{"prompt":"Hiss of a steam valve.","options":["🏭 Factory","🐍 Snake","🎈 Balloon","🚿 Shower"],"correct":0,"hint":"Steam release"},{"prompt":"Metallic clinking of tools.","options":["🧰 Tools","🍽️ Cutlery","💰 Coins","🔑 Keys"],"correct":0,"hint":"Organizing box"}]}', 20);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'B1', 'speaking', 'Describing Art', 'Art vocabulary practice', '{"type":"speak_and_compare","instructions":"Repeat the art description.","exercises":[{"prompt":"The landscape is breathtaking.","expected":"the landscape is breathtaking","hint":"Beautiful view"},{"prompt":"The artist used oil paints.","expected":"the artist used oil paints","hint":"Medium type"},{"prompt":"I love the abstract style.","expected":"i love the abstract style","hint":"Non-realistic"},{"prompt":"It captures a moment in time.","expected":"it captures a moment in time","hint":"Time capture"},{"prompt":"The colors are very vibrant.","expected":"the colors are very vibrant","hint":"Bright colors"}]}', 6),
('en', 'B1', 'speaking', 'Travel Planning', 'Booking a vacation', '{"type":"speak_and_compare","instructions":"Repeat the travel agent phrases.","exercises":[{"prompt":"I would like to book a flight.","expected":"i would like to book a flight","hint":"Booking action"},{"prompt":"Is there a direct flight available?","expected":"is there a direct flight available","hint":"No stops"},{"prompt":"I prefer an aisle seat, please.","expected":"i prefer an aisle seat please","hint":"Seat choice"},{"prompt":"Can I check my luggage here?","expected":"can i check my luggage here","hint":"Bags"},{"prompt":"What is the boarding time?","expected":"what is the boarding time","hint":"Time to board"}]}', 7),
('en', 'B1', 'speaking', 'Job Interview', 'Common interview phrases', '{"type":"speak_and_compare","instructions":"Practice your interview responses.","exercises":[{"prompt":"I have five years of experience.","expected":"i have five years of experience","hint":"Work history"},{"prompt":"I am a hard-working person.","expected":"i am a hard working person","hint":"Work ethic"},{"prompt":"I enjoy working in a team.","expected":"i enjoy working in a team","hint":"Teamwork"},{"prompt":"I am looking for new challenges.","expected":"i am looking for new challenges","hint":"Career goals"},{"prompt":"Thank you for the opportunity.","expected":"thank you for the opportunity","hint":"Polite closing"}]}', 8),
('en', 'B1', 'speaking', 'Making a Complaint', 'Polite ways to complain', '{"type":"speak_and_compare","instructions":"Practice being polite but firm.","exercises":[{"prompt":"Excuse me, there is a mistake.","expected":"excuse me there is a mistake","hint":"Polite opening"},{"prompt":"The service was quite slow today.","expected":"the service was quite slow today","hint":"Describing issue"},{"prompt":"I am not happy with this meal.","expected":"i am not happy with this meal","hint":"Direct complaint"},{"prompt":"Could I speak to the manager?","expected":"could i speak to the manager","hint":"Escalation"},{"prompt":"Thank you for fixing the issue.","expected":"thank you for fixing the issue","hint":"Resolution"}]}', 9),
('en', 'B1', 'speaking', 'Giving Advice', 'Suggesting solutions', '{"type":"speak_and_compare","instructions":"Practice modal verbs for advice.","exercises":[{"prompt":"You should try to relax more.","expected":"you should try to relax more","hint":"Recommendation"},{"prompt":"If I were you, I would go.","expected":"if i were you i would go","hint":"Conditional advice"},{"prompt":"Why don''t you call your friend?","expected":"why dont you call your friend","hint":"Suggestion"},{"prompt":"It might be a good idea.","expected":"it might be a good idea","hint":"Softening advice"},{"prompt":"You ought to see a doctor.","expected":"you ought to see a doctor","hint":"Strong advice"}]}', 10),
('en', 'B1', 'speaking', 'Tech Talk', 'Discussing gadgets', '{"type":"speak_and_compare","instructions":"Talk about modern technology.","exercises":[{"prompt":"My phone has a great camera.","expected":"my phone has a great camera","hint":"Feature"},{"prompt":"I use this app every day.","expected":"i use this app every day","hint":"Usage"},{"prompt":"The battery life is excellent.","expected":"the battery life is excellent","hint":"Performance"},{"prompt":"Is the software updated?","expected":"is the software updated","hint":"Maintenance"},{"prompt":"I cannot live without Wi-Fi.","expected":"i cannot live without wi fi","hint":"Necessity"}]}', 11),
('en', 'B1', 'speaking', 'Sharing News', 'Talking about events', '{"type":"speak_and_compare","instructions":"Practice conversational news.","exercises":[{"prompt":"Did you hear the latest news?","expected":"did you hear the latest news","hint":"Opening"},{"prompt":"It was all over the internet.","expected":"it was all over the internet","hint":"Source"},{"prompt":"I was so surprised by it.","expected":"i was so surprised by it","hint":"Reaction"},{"prompt":"Everyone is talking about it.","expected":"everyone is talking about it","hint":"Popularity"},{"prompt":"I hope things get better soon.","expected":"i hope things get better soon","hint":"Closing"}]}', 12),
('en', 'B1', 'speaking', 'A Great Story', 'Narrative practice', '{"type":"speak_and_compare","instructions":"Tell a short story fragment.","exercises":[{"prompt":"Once upon a time, there was.","expected":"once upon a time there was","hint":"Starting"},{"prompt":"Suddenly, the lights went out.","expected":"suddenly the lights went out","hint":"Action"},{"prompt":"We didn''t know what to do.","expected":"we didnt know what to do","hint":"Conflict"},{"prompt":"Finally, the sun came up.","expected":"finally the sun came up","hint":"Resolution"},{"prompt":"It was an amazing adventure.","expected":"it was an amazing adventure","hint":"Summary"}]}', 13),
('en', 'B1', 'speaking', 'Opinions on Food', 'Discussing flavors', '{"type":"speak_and_compare","instructions":"Express your culinary tastes.","exercises":[{"prompt":"This dish is a bit too spicy.","expected":"this dish is a bit too spicy","hint":"Taste"},{"prompt":"The sauce is rich and creamy.","expected":"the sauce is rich and creamy","hint":"Texture"},{"prompt":"I prefer sweet to savory.","expected":"i prefer sweet to savory","hint":"Preference"},{"prompt":"It smells absolutely delicious.","expected":"it smells absolutely delicious","hint":"Aroma"},{"prompt":"I would definitely order this again.","expected":"i would definitely order this again","hint":"Review"}]}', 14),
('en', 'B1', 'speaking', 'Socializing', 'Meeting people at a party', '{"type":"speak_and_compare","instructions":"Practice small talk phrases.","exercises":[{"prompt":"So, what do you do for work?","expected":"so what do you do for work","hint":"Question"},{"prompt":"I haven''t seen you here before.","expected":"i havent seen you here before","hint":"Observation"},{"prompt":"This is a wonderful party.","expected":"this is a wonderful party","hint":"Compliment"},{"prompt":"Would you like another drink?","expected":"would you like another drink","hint":"Offering"},{"prompt":"It was nice talking to you.","expected":"it was nice talking to you","hint":"Leaving"}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'B1', 'reading', 'The Roman Empire', 'A short history passage', '{"type":"read_and_choose","instructions":"Read and answer the questions.","passage":"The Roman Empire was one of the largest and most powerful empires in history. At its height, it controlled lands all around the Mediterranean Sea. The Romans built incredible roads, bridges, and aqueducts that lasted for centuries. Their language, Latin, influenced many modern languages.","exercises":[{"question":"What did the Romans build?","options":["Roads","Cars","Planes","Trains"],"correct":0},{"question":"Where was the empire centered?","options":["Mediterranean","Atlantic","Pacific","Arctic"],"correct":0},{"question":"What was their language?","options":["Latin","English","French","German"],"correct":0},{"question":"Was the empire small?","options":["No, it was large","Yes","Maybe","Unknown"],"correct":0},{"question":"Did they influence languages?","options":["Yes","No","A bit","Never"],"correct":0}]}', 6),
('en', 'B1', 'reading', 'Space Exploration', 'Understanding the universe', '{"type":"read_and_choose","instructions":"Read and answer.","passage":"Humans have always been curious about space. In 1969, Apollo 11 successfully landed on the moon. Today, scientists are planning missions to Mars. They use powerful telescopes to see distant galaxies. The international space station is a place where astronauts live and work.","exercises":[{"question":"When did humans land on the moon?","options":["1969","1959","1979","1989"],"correct":0},{"question":"Which planet is next for missions?","options":["Mars","Venus","Jupiter","Saturn"],"correct":0},{"question":"What do scientists use to see?","options":["Telescopes","Microscopes","Glasses","Cameras"],"correct":0},{"question":"Who lives on the space station?","options":["Astronauts","Doctors","Teachers","Drivers"],"correct":0},{"question":"Are humans curious about space?","options":["Yes","No","Sometimes","Rarely"],"correct":0}]}', 7),
('en', 'B1', 'reading', 'Famous Scientists', 'Biography fragments', '{"type":"read_and_choose","instructions":"Identify the scientist.","exercises":[{"question":"Who discovered gravity?","options":["Isaac Newton","Albert Einstein","Marie Curie","Darwin"],"correct":0},{"question":"Who worked on radioactivity?","options":["Marie Curie","Newton","Einstein","Tesla"],"correct":0},{"question":"Who developed relativity?","options":["Albert Einstein","Curie","Newton","Bell"],"correct":0},{"question":"Who studied evolution?","options":["Charles Darwin","Mendel","Curie","Newton"],"correct":0},{"question":"Who invented the lightbulb?","options":["Thomas Edison","Tesla","Bell","Ford"],"correct":1}]}', 8),
('en', 'B1', 'reading', 'Movie Review', 'Understanding opinions', '{"type":"read_and_choose","instructions":"Analyze the review.","passage":"The new action movie was exciting but a bit too long. The special effects were amazing, especially the explosions. However, the acting was not very good. Overall, it is worth watching if you like fast-paced films.","exercises":[{"question":"Was the movie exciting?","options":["Yes","No","Boring","Slow"],"correct":0},{"question":"What was amazing?","options":["Effects","Acting","Music","Script"],"correct":0},{"question":"Was the acting good?","options":["No","Yes","Perfect","Great"],"correct":0},{"question":"What was the problem?","options":["Length","Sound","Color","Title"],"correct":0},{"question":"Is it worth watching?","options":["Yes","No","Maybe","Never"],"correct":0}]}', 9),
('en', 'B1', 'reading', 'A Secret Recipe', 'Following instructions', '{"type":"read_and_choose","instructions":"Answer about the recipe.","passage":"To make the perfect pasta, boil water first. Add a pinch of salt. Cook the pasta for eight minutes. Meanwhile, heat the sauce in a small pan. Mix everything together and serve with cheese.","exercises":[{"question":"What do you do first?","options":["Boil water","Add salt","Cook pasta","Heat sauce"],"correct":0},{"question":"How long for pasta?","options":["8 mins","5 mins","10 mins","12 mins"],"correct":0},{"question":"What kind of pan for sauce?","options":["Small","Big","Deep","Frying"],"correct":0},{"question":"What should you add to water?","options":["Salt","Sugar","Oil","Pepper"],"correct":0},{"question":"What is the final step?","options":["Serve with cheese","Add water","Buy pasta","Clean pan"],"correct":0}]}', 10),
('en', 'B1', 'reading', 'Electronic Manual', 'Technical reading', '{"type":"read_and_choose","instructions":"Understand the manual.","passage":"Press the power button for three seconds to turn on the device. A blue light will flash. If the light is red, the battery is low. Use the included USB cable to charge. Avoid contact with water.","exercises":[{"question":"How long to press?","options":["3 seconds","1 second","5 seconds","10 seconds"],"correct":0},{"question":"What does blue light mean?","options":["Turning on","Low battery","Error","Charging"],"correct":0},{"question":"What if it is red?","options":["Low battery","Ready","Off","Full"],"correct":0},{"question":"How to charge?","options":["USB cable","Battery","Sun","Wall"],"correct":0},{"question":"Can you get it wet?","options":["No","Yes","Maybe","Unknown"],"correct":0}]}', 11),
('en', 'B1', 'reading', 'Formal Letter', 'Business communication', '{"type":"read_and_choose","instructions":"Identify the purpose.","passage":"Dear Mr. Jones, I am writing to confirm our meeting on Monday at 10 AM. Please bring the latest report with you. We will discuss the new budget in the conference room. Best regards, Jane Smith.","exercises":[{"question":"Who is the letter to?","options":["Mr. Jones","Jane Smith","Tom","Sarah"],"correct":0},{"question":"What time is the meeting?","options":["10 AM","9 AM","11 AM","2 PM"],"correct":0},{"question":"What should he bring?","options":["Report","Coffee","Laptop","Book"],"correct":0},{"question":"What is the topic?","options":["Budget","Holidays","Weather","Food"],"correct":0},{"question":"Who wrote the letter?","options":["Jane Smith","Mr. Jones","The boss","Secretary"],"correct":0}]}', 12),
('en', 'B1', 'reading', 'Weather Report', 'Deep atmosphere', '{"type":"read_and_choose","instructions":"Analyze the weather.","passage":"A cold front is moving in from the north. Expect heavy rain and strong winds this evening. Temperatures will drop to five degrees. Driving will be dangerous due to low visibility. Stay indoors if possible.","exercises":[{"question":"Where is the front from?","options":["North","South","East","West"],"correct":0},{"question":"What is expected?","options":["Rain and wind","Sun","Snow","Heat"],"correct":0},{"question":"What is the temp?","options":["5 degrees","10 degrees","0 degrees","15 degrees"],"correct":0},{"question":"Is driving safe?","options":["No","Yes","Very","Maybe"],"correct":0},{"question":"What is suggested?","options":["Stay indoors","Go for run","Travel","Swim"],"correct":0}]}', 13),
('en', 'B1', 'reading', 'Mystery Story', 'Inference practice', '{"type":"read_and_choose","instructions":"Solve the mini mystery.","passage":"The window was open, and the curtains were fluttering. The silver vase was missing from the table. There were muddy footprints on the carpet. The cat was sleeping peacefully on the sofa.","exercises":[{"question":"What was missing?","options":["Vase","Cat","Curtains","Table"],"correct":0},{"question":"Was the window closed?","options":["No, open","Yes","Unknown","Broken"],"correct":0},{"question":"What was on the carpet?","options":["Footprints","Water","Milk","Glass"],"correct":0},{"question":"Where was the cat?","options":["Sofa","Window","Table","Garden"],"correct":0},{"question":"Was the cat guilty?","options":["Probably not","Yes","Maybe","Always"],"correct":0}]}', 14),
('en', 'B1', 'reading', 'Travel Blog', 'Vlogging style', '{"type":"read_and_choose","instructions":"Understanding tone.","passage":"I just arrived in Tokyo and it is incredible! The neon lights are everywhere. The food is so fresh and tasty. I am staying in a tiny hotel room, which is a bit strange, but everything else is perfect.","exercises":[{"question":"Where is the blogger?","options":["Tokyo","Paris","New York","London"],"correct":0},{"question":"How is the food?","options":["Fresh","Salty","Old","Bad"],"correct":0},{"question":"What is strange?","options":["Hotel room","Lights","Food","People"],"correct":0},{"question":"Are the lights bright?","options":["Yes, neon","No","Dark","Dim"],"correct":0},{"question":"Is the blogger happy?","options":["Yes","No","Angry","Sad"],"correct":0}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'B1', 'writing', 'Urban Description', 'Describe a city scene', '{"type":"guided_writing","instructions":"Answer with full sentences.","exercises":[{"question":"What can you see in a city?","starter":"In a city, I can see","example":"In a city, I can see tall buildings and busy streets.","hint":"Buildings and people"},{"question":"How is the noise?","starter":"The noise is","example":"The noise is very loud because of the cars.","hint":"Volume"},{"question":"Where do people work?","starter":"People work in","example":"People work in offices, shops, and banks.","hint":"Location"},{"question":"Do you like cities?","starter":"I like cities because","example":"I like cities because there is always something to do.","hint":"Personal opinion"},{"question":"What is a problem?","starter":"A problem in cities is","example":"A problem in cities is the air pollution.","hint":"Negative aspect"}]}', 6),
('en', 'B1', 'writing', 'Expressing Opinions', 'Write about technology', '{"type":"guided_writing","instructions":"Give your thoughts.","exercises":[{"question":"Is technology good?","starter":"I think technology is","example":"I think technology is very useful in daily life.","hint":"General view"},{"question":"Why?","starter":"It helps us to","example":"It helps us to communicate with people far away.","hint":"Reason"},{"question":"What is the best gadget?","starter":"The best gadget is","example":"The best gadget is the smartphone.","hint":"Choice"},{"question":"Any downsides?","starter":"One downside is","example":"One downside is that it can be addictive.","hint":"Negative"},{"question":"Future of tech?","starter":"In the future, I think","example":"In the future, I think we will have flying cars.","hint":"Prediction"}]}', 7),
('en', 'B1', 'writing', 'Giving Advice', 'Writing helpful tips', '{"type":"guided_writing","instructions":"Advise a friend.","exercises":[{"question":"Friend is tired?","starter":"You should","example":"You should go to bed earlier tonight.","hint":"Fatigue"},{"question":"Friend is bored?","starter":"Why don''t you","example":"Why don''t you start a new hobby?","hint":"Boredom"},{"question":"Friend is lost?","starter":"If I were you, I would","example":"If I were you, I would check the map.","hint":"Navigation"},{"question":"Friend is hungry?","starter":"You could","example":"You could order some pizza.","hint":"Hunger"},{"question":"Friend is sad?","starter":"It might be good to","example":"It might be good to talk to someone.","hint":"Mood"}]}', 8),
('en', 'B1', 'writing', 'Formal Email', 'Practice business writing', '{"type":"guided_writing","instructions":"Complete the email.","exercises":[{"question":"Subject line?","starter":"Subject:","example":"Subject: Meeting Request","hint":"Title"},{"question":"Opening?","starter":"Dear ","example":"Dear Mr. Smith,","hint":"Greeting"},{"question":"Reason to write?","starter":"I am writing to","example":"I am writing to inquire about the job.","hint":"Purpose"},{"question":"Attachment?","starter":"I have attached my","example":"I have attached my CV for your review.","hint":"Files"},{"question":"Closing?","starter":"Sincerely,","example":"Sincerely, John Doe.","hint":"Sign-off"}]}', 9),
('en', 'B1', 'writing', 'Job Application', 'Short bio for work', '{"type":"guided_writing","instructions":"Write a short profile.","exercises":[{"question":"Your skills?","starter":"I am skilled in","example":"I am skilled in coding and design.","hint":"Abilities"},{"question":"Experience?","starter":"I have worked for","example":"I have worked for three years in IT.","hint":"History"},{"question":"Why this job?","starter":"I want this job because","example":"I want this job because I love challenges.","hint":"Motivation"},{"question":"Strengths?","starter":"My main strength is","example":"My main strength is problem solving.","hint":"Positives"},{"question":"Availability?","starter":"I can start","example":"I can start from next month.","hint":"Timing"}]}', 10),
('en', 'B1', 'writing', 'Comparison', 'Compare two things', '{"type":"guided_writing","instructions":"Write comparisons.","exercises":[{"question":"City vs Country?","starter":"The city is","example":"The city is noisier than the countryside.","hint":"Environment"},{"question":"Book vs Movie?","starter":"A book is usually","example":"A book is usually more detailed than a movie.","hint":"Media"},{"question":"Summer vs Winter?","starter":"Summer is","example":"Summer is much hotter than winter.","hint":"Seasons"},{"question":"Tea vs Coffee?","starter":"Tea is","example":"Tea is healthier but coffee gives more energy.","hint":"Drinks"},{"question":"Plane vs Train?","starter":"A plane is","example":"A plane is faster but a train is more relaxing.","hint":"Travel"}]}', 11),
('en', 'B1', 'writing', 'Summarizing', 'Condensing information', '{"type":"guided_writing","instructions":"Condense the story.","exercises":[{"question":"What happened first?","starter":"First, the character","example":"First, the character found a map.","hint":"Start"},{"question":"What was the middle?","starter":"Then, they traveled","example":"Then, they traveled to the island.","hint":"Action"},{"question":"What was the climax?","starter":"Suddenly, they found","example":"Suddenly, they found the treasure.","hint":"Peak"},{"question":"How did it end?","starter":"In the end, everyone","example":"In the end, everyone was happy.","hint":"Conclusion"},{"question":"Moral?","starter":"The moral is","example":"The moral is that courage pays off.","hint":"Lesson"}]}', 12),
('en', 'B1', 'writing', 'Future Intentions', 'Writing about goals', '{"type":"guided_writing","instructions":"Predict your future.","exercises":[{"question":"Learning goals?","starter":"I plan to learn","example":"I plan to learn to speak French.","hint":"Knowledge"},{"question":"Career goals?","starter":"I hope to become","example":"I hope to become a manager.","hint":"Work"},{"question":"Travel goals?","starter":"I am going to visit","example":"I am going to visit Japan.","hint":"Trips"},{"question":"Health goals?","starter":"I will try to","example":"I will try to exercise every day.","hint":"Body"},{"question":"Personal goals?","starter":"I want to","example":"I want to be more patient.","hint":"Self"}]}', 13),
('en', 'B1', 'writing', 'Personal Experience', 'Writing about the past', '{"type":"guided_writing","instructions":"Share a memory.","exercises":[{"question":"When did it happen?","starter":"It happened","example":"It happened last summer.","hint":"Time"},{"question":"Where?","starter":"I was in","example":"I was in a small town.","hint":"Place"},{"question":"What happened?","starter":"I saw","example":"I saw a very famous actor.","hint":"Event"},{"question":"How did you feel?","starter":"I felt","example":"I felt extremely excited.","hint":"Emotion"},{"question":"Why do you remember?","starter":"I remember it because","example":"I remember it because it was so rare.","hint":"Impact"}]}', 14),
('en', 'B1', 'writing', 'Unscramble Sentences', 'Complex sentence structure', '{"type":"unscramble","instructions":"Unscramble the B1 level sentence.","exercises":[{"scrambled":"been have I studying for English years three.","expected":"I have been studying English for three years.","hint":"Present perfect continuous"},{"scrambled":"If it tomorrow rains, will we stay home.","expected":"If it rains tomorrow, we will stay home.","hint":"Conditionals"},{"scrambled":"The movie which saw we was yesterday great.","expected":"The movie which we saw yesterday was great.","hint":"Relative clauses"},{"scrambled":"I don''t know where they going are now.","expected":"I don''t know where they are going now.","hint":"Indirect questions"},{"scrambled":"She said that would she come later.","expected":"She said that she would come later.","hint":"Reported speech"}]}', 15);
